import java.io.*;
import java.util.*;

public class Main {
    private static List<Integer> findLeaders(int[] arr) {
        int n = arr.length;
        List<Integer> rev = new ArrayList<>();
        int maxFromRight = Integer.MIN_VALUE;
        for (int i = n - 1; i >= 0; i--) {
            if (arr[i] > maxFromRight) {
                rev.add(arr[i]);
                maxFromRight = arr[i];
            }
        }
        Collections.reverse(rev);
        return rev;
    }

    public static void main(String[] args) throws Exception {
        // Read entire input as a single string (may contain literal "\\n" sequences)
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawBuilder = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawBuilder.append(line);
            rawBuilder.append('\n');
        }
        String raw = rawBuilder.toString();
        // Replace escaped newlines with actual newlines
        raw = raw.replace("\\n", "\n");
        // Use a Scanner on the processed input
        Scanner sc = new Scanner(raw);
        StringBuilder sb = new StringBuilder();
        if (!sc.hasNextInt()) {
            System.out.print("");
            return;
        }
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
            }
            List<Integer> leaders = findLeaders(arr);
            for (int i = 0; i < leaders.size(); i++) {
                if (i > 0) sb.append(' ');
                sb.append(leaders.get(i));
            }
            sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

